private reinforceNodeDimensions() {
  d3.select(this.svg)
    .selectAll(`.${NODE_CLASS} .label`)
    .each((nodeId, idx, group) => {
      const node = group[idx];
      const d3Node = d3.select(node);
      const {width, height} = this.graph.node(nodeId as string) as DagreRegularNode;

      d3Node
        .select('g')
        .attr('transform', `translate(${-width / 2}, ${-height / 2})`)
        .select('foreignObject')
        .attr('width', width)
        .attr('height', height);
    });
}

applyStylesToKeyframe() {
  if (this._pendingStyles.size == 0) return;

  this._pendingStyles.forEach((val, prop) => {
    this._currentKeyframe.set(prop, val);
  });
  this._pendingStyles.clear();

  this._localTimelineStyles.forEach((val, prop) => {
    if (!this._currentKeyframe.has(prop)) {
      this._currentKeyframe.set(prop, val);
    }
  });
}

function objEquals(a: {[key: string]: any}, b: {[key: string]: any}): boolean {
  const k1 = Object.keys(a);
  const k2 = Object.keys(b);
  if (k1.length != k2.length) return false;
  for (let i = 0; i < k1.length; i++) {
    const prop = k1[i];
    if (!b.hasOwnProperty(prop) || a[prop] !== b[prop]) return false;
  }
  return true;
}

