(
props: {[prop: string]: Descriptor} | Descriptor[],
parent: Property | null = null,
): Property[] =>
Object.entries(props)
.map(([name, val]) => ({name, descriptor: val, parent}))
.sort((a, b) => {
  const parsedA = parseInt(a.name, 10);
  const parsedB = parseInt(b.name, 10);

  if (isNaN(parsedA) || isNaN(parsedB)) {
    return a.name > b.name ? 1 : -1;
  }

  return parsedA - parsedB;
})

private getColorByFrameRate(framerate: number): string {
  if (framerate >= 60) {
    return 'var(--dynamic-green-01)';
  } else if (60 > framerate && framerate >= 30) {
    return 'var(--dynamic-yellow-01)';
  } else if (30 > framerate && framerate >= 15) {
    return 'var(--dynamic-red-02)';
  }
  return 'var(--dynamic-red-01)';
}

