(p0: number, p1: number, p2: number, p3: number, refPoint: number): number[] => {
  p0 -= refPoint;
  p1 -= refPoint;
  p2 -= refPoint;
  p3 -= refPoint;

  const roots = solveCubicEquation(p3 - 3 * p2 + 3 * p1 - p0, 3 * p2 - 6 * p1 + 3 * p0, 3 * p1 - 3 * p0, p0);

  return roots.filter((root) => root >= 0 && root <= 1);
}

(
  p0: number[],
  p1: number[],
  p2: number[],
  p3: number[],
  progression: number
): number[] => {
  return solveCubicBezier(p0[1], p1[1], p2[1], p3[1], progression).map((tValue) => {
    return solveCubicParametricEquation(p0[0], p1[0], p2[0], p3[0], tValue);
  });
}

export function mapResponse<T, E, R1, R2>(
  observer: MapResponseObserver<T, E, R1, R2>
): (source$: Observable<T>) => Observable<R1 | R2> {
  return (source$) =>
    source$.pipe(
      map((value) => observer.next(value)),
      catchError((error) => of(observer.error(error)))
    );
}
